#include <bits/stdc++.h>
using namespace std;
const int maxn=1e7+5,mod=100003;
struct node{
	vector<int> e;
	int d=-1,fas;
}v[maxn];
queue<int> q;
int n,m;
void cheek(int dis,int id,int fas){
	if(v[id].d==-1){
		v[id].d=dis;
		v[id].fas=fas;
		q.push(id);
	}else if(v[id].d==dis){
		v[id].fas=(v[id].fas+fas)%mod;
	}
}
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1,x,y;i<=m;i++){
		cin>>x>>y;
		v[x].e.push_back(y);
		v[y].e.push_back(x);
	}
	cheek(0,1,1);
	while(q.size()){
		int p=q.front();
		q.pop();
		for(auto x:v[p].e){
			cheek(v[p].d+1,x,v[p].fas);
		}
	}
	for(int i=1;i<=n;i++){
		cout<<v[i].fas<<"\n";
	}
	return 0;
}
